  })

  it('returns false for non-matching regions', () => {
    assert.equal(isInRegion({ countryCode: 'JP' }, ['US', 'CA']), false)
  })

  it('returns false when countryCode is undefined', () => {
    assert.equal(isInRegion({}, ['US', 'CA']), false)
  })
})

describe('geoDistance()', () => {
  it('calculates New York to London (~5570 km)', () => {
    // New York: 40.7128°N, 74.0060°W — London: 51.5074°N, 0.1278°W
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
